class Solution:
    def minAreaRect(self, points):
        pts = set(map(tuple, points))
        best = float('inf')
        n = len(points)
        for i in range(n):
            for j in range(i + 1, n):
                x1, y1 = points[i]
                x2, y2 = points[j]
                if x1 == x2 or y1 == y2:
                    continue
                if (x1, y2) in pts and (x2, y1) in pts:
                    area = abs(x1 - x2) * abs(y1 - y2)
                    if area < best:
                        best = area
        return 0 if best == float('inf') else best

